head.script:
	// 전역변수 선언
	scwin.selectRow;
	scwin.searchPopupType = "";

	/**
	 * 화면 초기화에 필요한 로직을 수행한다.
	 * @param
	 * @return
	 */
	scwin.initScreen = function() {
		// 화면초기화 공통 함수 호출
		comLib.initForm($p, "ECSZZ1500000", {"initScreenCallback" : scwin.searchDatas});
	};

	/**
	 * 화면 초기 데이터들을 조회한다.
	 * @param
	 * @return
	 */
	scwin.searchDatas = function() {
		// 로그인한 사용자 ID 변수설정
		scwin.usrId = comLib.getUsrId();

		// 작업일자 설정한다.
		scwin.today = utilLib.getCurrentDate();

		// 부서코드 조회
		scwin.setDeptCd();

		// 화면 오픈시 자동조회를 한다.
		comLib.setEnterKeyEvent(grpInqire, scwin.btnInqire1_onclick);
		comLib.setEnterKeyEvent(grpInqire1, scwin.btnInqire2_onclick);
	};

	/**
	 * 부서코드 조회
	 * @param
	 * @return
	 */
	scwin.setDeptCd = function() {
		var requestData = {};

		var option = {
			action : "sc/cmmncd/retrieveDeptInqire.do",
			reqData : requestData,
			resData : dltDeptCd,
			success : "scwin.setCdCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 초기코드 설정 CallBack 실행
	 * @param <Object> resBody
	 * @return
	 */
	scwin.setCdCallback = function(resBody, e) {
		// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
		scwin.setAthrSysDivCd();
	};

	/**
 	 * 공통 코드 조회 콜백
	 * @param
	 * @return
	 */
	scwin.setAthrSysDivCd = function () {
		var requestData = {};
		requestData.data = {"usrId" : scwin.usrId, "sysDivCd" : "SCM_0000"};

		var option = {
			action : "sc/authmng/retrieveAthrSysDivCd.do",
			reqData : requestData,
			resData : dltSysDivCdList,
			success : "scwin.retrieveAthrSysDivCdCallback",
			isShowMeg : false
		};
		ajaxLib.requestAjaxSyncCode($p, option);
	};

	/**
	 * 조회 CallBack 실행
	 * @param <Object> resBody
	 * @return
	 */
	scwin.retrieveAthrSysDivCdCallback = function (resBody, e) {
		if (dltSysDivCdList.getRowCount() == 0) {
			// 시스템관리자만 접근이 가능합니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
			return;
		}

		scwin.inqireBtnInfo();
	};

	/**
	 * 버튼권한값 DB 가져오기
	 * @param
	 * @return
	*/
	scwin.inqireBtnInfo = function() {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();

		var option = {
			action : "zz/authmng/retrieveBtnInfo.do",
			reqData : requestData,
			resData : dltBtnAthrList,
			success : "scwin.inqireBtnInfoCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 버튼권한값 DB 가져오기
	 * @param
	 * @return
	*/
	scwin.inqireBtnInfoCallback = function(resBody, e) {
		if (resBody.message.code == "success") {
			//console.log("조회된 데이터는 총 " + dltBtnAthrList.getRowCount() + " 건 입니다.");
		}

		scwin.btnInqire1_onclick();
	};

	/**
	 * 사용자목록 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire1_onclick = function() {
		var requestData = {};
		requestData.dmaInqireParam = dmaInqireParam.getJSON();

		var option = {
			action : "zz/authmng/retrieveUsr.do",
			reqData : requestData,
			resData : dltUsrList,
			success : "scwin.inqireCallback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqireCallback = function(resBody) {
		if (resBody.message.code == "success") {
			txtCnt1.setValue(dltUsrList.getRowCount());
			txtCnt2.setValue("0");
		} else {
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 사용자목록 그리드에서 사용자를 선택시 해당 사용자의 메뉴조회를 한다.
	 * @param <Int> row
	 * @param <Int> col
	 * @return
	 */
	scwin.grdUsrList_oncellclick = function(row, col) {
		var strUsrId = dltUsrList.getCellData(row, "usrId");

		dmaInqireUsrMenu.set("usrId", strUsrId);
		dmaInqireUsrMenu.set("intnSysDivCd", comLib.getSysDivCd());
		dmaInqireUsrMenu.set("menuNm", "");

		scwin.btnInqire2_onclick();
	};

	/**
	 * 사용자목록에서 선택한 사용자를 기준으로 메뉴에 설정된 정보를 조회한다.
	 * @param
	 * @return
	 */
	scwin.btnInqire2_onclick = function() {
		// 권한ID를 지정하고 조회하도록 한다.
		var usrId = dmaInqireUsrMenu.get("usrId");

		if (usrId == "") {
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00004", "사용자ID"));
			return;
		}

		var requestData = {};
		requestData.dmaInqireUsrMenu = dmaInqireUsrMenu.getJSON();

		var option = {
			action : "zz/authmng/retrieveIntnUsrMenu.do",
			reqData : requestData,
			resData : dltIntnUsrMenu,
			success : "scwin.inqire2Callback",
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 조회 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.inqire2Callback = function(resBody) {
		if (resBody.message.code == "success") {
			txtCnt2.setValue(dltIntnUsrMenu.getRowCount());

			if (dltIntnUsrMenu.getRowCount() > 0) {
				var inqireUsrId = dmaInqireUsrMenu.get("usrId");

				for (var idx = 0; idx < dltIntnUsrMenu.getRowCount(); idx++) {
					var usrId = dltIntnUsrMenu.getCellData(idx, "usrId");

					if (usrId != null && usrId != "") {
						dltIntnUsrMenu.setCellData(idx, "grantYn", "Y");
						grdIntnUsrMenu.setCellReadOnly(idx, "btnAthrList", false);
					} else {
						dltIntnUsrMenu.setCellData(idx, "usrId", inqireUsrId);
						dltIntnUsrMenu.setCellData(idx, "grantYn", "N");
						grdIntnUsrMenu.setCellReadOnly(idx, "btnAthrList", true);
					}
				}

				dltIntnUsrMenu.modifyAllStatus("R");
			}
		} else {
			comLib.alert($p, "fail");
		}
	};

	/**
	 * 사용자별메뉴 등록/수정한다.
	 * @param
	 * @return
	 */
	scwin.btnSave_onclick = function() {
		if (dltIntnUsrMenu.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		scwin.saveCnfirm();
	};

	/**
	 * 저장, 삭제 여부를 물어본다.
	 * @param
	 * @return
	 */
	scwin.saveCnfirm = function() {
		// 저장할것인지 confirm
		comLib.confirm($p, utilLib.getMessage("SCM.INFO.00239"), "scwin.saveConfirmCallback");
	};

	/**
	 * 수정/저장 ComfirmCallBack 실행한다.
	 * @param
	 * @return
	 */
	scwin.saveConfirmCallback = function() {
		var requestData = {};
		requestData.dltIntnUsrMenu = dltIntnUsrMenu.getModifiedJSON();

		var option = {
			action : "zz/authmng/saveIntnUsrMenu.do",
			reqData : requestData,
			success : "scwin.saveIntnUsrMenuCallback",
			savedToken : true,
			isShowMeg : false
		};
		ajaxLib.executeAjax($p, option);
	};

	/**
	 * 수정/저장 CallBack 실행한다.
	 * @param <Object> resBody
	 * @return
	 */
	scwin.saveIntnUsrMenuCallback = function(resBody) {
		// 저장되었습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00327"));
		if (dltIntnUsrMenu.getMatchedData("grantYn", "Y").length > 0) {
			scwin.btnInqire2_onclick();
		} else {
			scwin.btnCancl_onclick();
		}
	};

	/**
	 * 작업중이던 내용을 취소한다.
	 * @param
	 * @return
	 */
	scwin.btnCancl_onclick = function() {
		// 작업중이던 dataMap을 초기화한다.
		dmaInqireParam.reset();
		dmaInqireUsrMenu.reset();
		dltIntnUsrMenu.removeAll();

		txtCnt2.setValue("0");

		scwin.btnInqire1_onclick();
	};

	/**
	 * 사용자 조회
	 * @param
	 * @return
	 */
	scwin.btnInqireUsr_onclick = function() {
		var url = comLib.HRM_POP_URL + "/ui/hrm/zz/searchmng/HRMZZ20000001.xml";

		//팝업창 옵션
		var option = {
			popupID : "HRMZZ20000001",
			width : 800,
			height : 500,
			title : "사용자 검색"
		};

		var strEnc = comLib.dataDecEnc(utilLib.getDate(), "E"); //암호화 키값
		var usrInfo; //세션정보 및 윈도우 타이틀
		usrInfo = JSON.stringify(comLib.getUserInfo4Param(strEnc, encodeURI(option.title)));

		var jsonObj = {
			// 필수값
			userInfo : usrInfo,
			closeCallbackFncName : "scwin.inqireUsrCallback",
			popupId : option.popupID
		};

		comLib.openPostWinPopup($p, url, option, jsonObj);
	};

	/**
	* 사용자 검색 CallBack 실행
	* @param <Object> returnValue
	* @param <String> popupId
	* @return
	*/
	scwin.inqireUsrCallback = function(returnValue, popupId) {
		var selectedOrg = returnValue;

		if (scwin.searchPopupType == "I") {
			// 사용자 추가 시 사용자 필드에 값을 넣는다.
			dltUsrList.setCellData(scwin.selectRow, "usrId", selectedOrg.usrId);
			dltUsrList.setCellData(scwin.selectRow, "usrNm", selectedOrg.usrNm);
			dltUsrList.setCellData(scwin.selectRow, "usrDeptCd", selectedOrg.usrDeptCd);
			dltUsrList.setCellData(scwin.selectRow, "usrDeptNm", selectedOrg.usrDeptNm);
		} else {
			// 검색 시 검색 필드에 값을 넣는다.
			dmaInqireParam.set("usrId", selectedOrg.usrId);
			dmaInqireParam.set("usrNm", selectedOrg.usrNm);
		}
		scwin.searchPopupType = "";
	};

	/**
	 * 사용자 행 추가
	 * @param
	 * @return
	*/
	scwin.btnAddRow1_onclick = function() {
		var insertIndex = dltUsrList.insertRow();

		grdUsrList.setFocusedCell(insertIndex, "usrNm", true);

		scwin.selectRow = insertIndex;
		scwin.searchPopupType = "I";
		scwin.btnInqireUsr_onclick();
	};

	/**
	 * 해더 클릭 시 자동 체크되도록 한다.
	 * @param <Object> info
	 * @return
	 */
	scwin.grdIntnUsrMenu_onheaderclick = function(headerId) {
		if (headerId == "hGrantYn") {
			for (var idx = 0; idx < dltIntnUsrMenu.getRowCount(); idx++) {
				if (dltIntnUsrMenu.getCellData(idx, "grantYn") == "Y") {
					grdIntnUsrMenu.setCellReadOnly(idx, "btnAthrList", false);
					dltIntnUsrMenu.setCellData(idx, "btnAthrList", "Q,S,D,N,CC,E,EU");
					dltIntnUsrMenu.modifyRowStatus(idx, "C");
				} else {
					grdIntnUsrMenu.setCellReadOnly(idx, "btnAthrList", true);
					dltIntnUsrMenu.setCellData(idx, "btnAthrList", "");
					dltIntnUsrMenu.deleteRow(idx);
				}
			}
		}
	};

	/**
	 * 사용자그룹명 변경시 자동 체크되도록 한다.
	 * @param <Object> info
	 * @return
	 */
	scwin.grdIntnUsrMenu_onviewchange = function(info) {
		var targetRow = info.rowIndex;
		var targetCol = info.colIndex;
		var oldValue = info.oldValue;
		var newValue = info.newValue;

		if (targetCol == 1) {
			if (newValue == "Y") {
				grdIntnUsrMenu.setCellReadOnly(targetRow, "btnAthrList", false);
				dltIntnUsrMenu.setCellData(targetRow, "btnAthrList", "Q,S,D,N,CC,E,EU");
				dltIntnUsrMenu.modifyRowStatus(targetRow, "C");
			} else {
				grdIntnUsrMenu.setCellReadOnly(targetRow, "btnAthrList", true);
				dltIntnUsrMenu.setCellData(targetRow, "btnAthrList", "");
				dltIntnUsrMenu.deleteRow(targetRow);
			}
		}
	};
